package com.ruoyi.modules.invest.benefit.calculation.controller;
import com.ruoyi.common.annotation.Log;import com.ruoyi.common.core.controller.BaseController;import com.ruoyi.common.core.domain.AjaxResult;import com.ruoyi.common.core.page.TableDataInfo;import com.ruoyi.common.enums.BusinessType;import com.ruoyi.modules.invest.benefit.calculation.domain.*;import com.ruoyi.modules.invest.benefit.calculation.service.IInvestBenefitCalculationService;import org.apache.shiro.authz.annotation.RequiresPermissions;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.web.bind.annotation.*;import java.util.List;@RestController@RequestMapping("/invest/benefit/calculation")public class InvestBenefitCalculationController extends BaseController{@Autowired private IInvestBenefitCalculationService service;@RequiresPermissions("invest:benefit:calc:list")@GetMapping("/list")public TableDataInfo list(InvestBenefitCalculation c){startPage();return getDataTable(service.selectList(c));}@RequiresPermissions("invest:benefit:calc:list")@GetMapping("/{id}")public AjaxResult get(@PathVariable Long id){return success(service.selectById(id));}@RequiresPermissions("invest:benefit:calc:add")@Log(title="效益测算",businessType=BusinessType.INSERT)@PostMapping public AjaxResult add(@RequestBody InvestBenefitCalculation c){return toAjax(service.insert(c));}@RequiresPermissions("invest:benefit:calc:edit")@Log(title="效益测算",businessType=BusinessType.UPDATE)@PutMapping public AjaxResult edit(@RequestBody InvestBenefitCalculation c){return toAjax(service.update(c));}@RequiresPermissions("invest:benefit:calc:remove")@DeleteMapping("/{ids}")public AjaxResult del(@PathVariable Long[] ids){return toAjax(service.deleteByIds(ids));}@RequiresPermissions("invest:benefit:calc:edit")@PostMapping("/{id}/items")public AjaxResult items(@PathVariable Long id,@RequestBody List<InvestBenefitCalcItem> items){return toAjax(service.saveItems(id,items));}@RequiresPermissions("invest:benefit:calc:calculate")@PostMapping("/{id}/calculate")public AjaxResult calculate(@PathVariable Long id){return toAjax(service.calculate(id));}@RequiresPermissions("invest:benefit:calc:submit")@PostMapping("/submit/{id}")public AjaxResult submit(@PathVariable Long id){return toAjax(service.submit(id));}}